INSERT INTO dim_player (
    id, create_time, modify_time, version, deleted,
    tenant_id, tenant_plat_id, vip_id,
    username, real_name, mobile,
    regist_device, regist_ip, regist_address,
    channel_id, follower_id,
    email, wechat,
    agentable, rate_agent_id, rebate_agent_id, channel_partner_id,
    sex, birthday, mobile_checked, enabled,
    device_key, first_auto_regist, mobile_area_code,
    checked_time, type, agent_time,
    regist_domain, s_create_time, mobile_attribution,
    password, speed_transfer_type, link_id, premium_show_flag, agent_level, limit_value
)
SELECT
    990200 + n.seq AS id,
    TIMESTAMPADD(
        MINUTE,
        FLOOR(MOD(n.seq, 52) / 4) * 30 + MOD(n.seq, 4) * 7,
        TIMESTAMPADD(DAY, FLOOR(n.seq / 52), '2026-04-15 09:00:00')
    ) AS create_time,
    TIMESTAMPADD(
        MINUTE,
        FLOOR(MOD(n.seq, 52) / 4) * 30 + MOD(n.seq, 4) * 7,
        TIMESTAMPADD(DAY, FLOOR(n.seq / 52), '2026-04-15 09:00:00')
    ) AS modify_time,
    0 AS version,
    0 AS deleted,
    980001 AS tenant_id,
    990001 AS tenant_plat_id,
    MOD(n.seq, 4) AS vip_id,
    CONCAT('kb_m', 990200 + n.seq) AS username,
    CONCAT('Mass ', 990200 + n.seq) AS real_name,
    CONCAT('13800', LPAD(990200 + n.seq, 6, '0')) AS mobile,
    CASE WHEN MOD(n.seq, 2) = 0 THEN 1 ELSE 2 END AS regist_device,
    CONCAT('10.20.', FLOOR(n.seq / 32), '.', MOD(n.seq, 32) + 1) AS regist_ip,
    CASE MOD(n.seq, 8)
        WHEN 0 THEN 'Shanghai'
        WHEN 1 THEN 'Beijing'
        WHEN 2 THEN 'Guangzhou'
        WHEN 3 THEN 'Shenzhen'
        WHEN 4 THEN 'Hangzhou'
        WHEN 5 THEN 'Nanjing'
        WHEN 6 THEN 'Suzhou'
        ELSE 'Ningbo'
    END AS regist_address,
    CASE MOD(n.seq, 4)
        WHEN 0 THEN 990011
        WHEN 1 THEN 990012
        WHEN 2 THEN 990013
        ELSE 990014
    END AS channel_id,
    0 AS follower_id,
    CONCAT('kb_m', 990200 + n.seq, '@kb.test') AS email,
    CONCAT('wx_kb_m', 990200 + n.seq) AS wechat,
    0 AS agentable,
    CASE MOD(n.seq, 4)
        WHEN 0 THEN 980031
        WHEN 1 THEN 980032
        WHEN 2 THEN 980031
        ELSE 980032
    END AS rate_agent_id,
    0 AS rebate_agent_id,
    CASE MOD(n.seq, 4)
        WHEN 0 THEN 980021
        WHEN 1 THEN 980022
        WHEN 2 THEN 980021
        ELSE 980022
    END AS channel_partner_id,
    1 AS sex,
    0 AS birthday,
    1 AS mobile_checked,
    1 AS enabled,
    CONCAT('dev-', 990200 + n.seq) AS device_key,
    0 AS first_auto_regist,
    '+86' AS mobile_area_code,
    TIMESTAMPADD(
        MINUTE,
        FLOOR(MOD(n.seq, 52) / 4) * 30 + MOD(n.seq, 4) * 7 + 1,
        TIMESTAMPADD(DAY, FLOOR(n.seq / 52), '2026-04-15 09:00:00')
    ) AS checked_time,
    1 AS type,
    '1970-01-01 08:00:00.000000' AS agent_time,
    CASE MOD(n.seq, 4)
        WHEN 0 THEN 'kb-a.example.com'
        WHEN 1 THEN 'kb-b.example.com'
        WHEN 2 THEN 'kb-c.example.com'
        ELSE 'kb-d.example.com'
    END AS regist_domain,
    TIMESTAMPADD(
        MINUTE,
        FLOOR(MOD(n.seq, 52) / 4) * 30 + MOD(n.seq, 4) * 7,
        TIMESTAMPADD(DAY, FLOOR(n.seq / 52), '2026-04-15 09:00:00')
    ) AS s_create_time,
    CASE MOD(n.seq, 8)
        WHEN 0 THEN 'Shanghai'
        WHEN 1 THEN 'Beijing'
        WHEN 2 THEN 'Guangzhou'
        WHEN 3 THEN 'Shenzhen'
        WHEN 4 THEN 'Hangzhou'
        WHEN 5 THEN 'Nanjing'
        WHEN 6 THEN 'Suzhou'
        ELSE 'Ningbo'
    END AS mobile_attribution,
    '***' AS password,
    1 AS speed_transfer_type,
    NULL AS link_id,
    1 AS premium_show_flag,
    NULL AS agent_level,
    NULL AS limit_value
FROM (
    SELECT ones.n + tens.n * 10 + hundreds.n * 100 AS seq
    FROM (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
        UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9
    ) ones
    CROSS JOIN (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
        UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9
    ) tens
    CROSS JOIN (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2
    ) hundreds
) n
WHERE n.seq < 260;
INSERT INTO dwd_player_login_log (
    id, create_time, modify_time, version, deleted,
    tenant_id, tenant_plat_id,
    player_id, player_username,
    ip, device, address,
    channel_id, category, interval_time,
    device_key, login_channel_id, login_domain, s_create_time
)
SELECT
    1000101 + p.player_seq * 5 + l.seq AS id,
    TIMESTAMPADD(
        MINUTE,
        CASE l.seq
            WHEN 0 THEN 606
            WHEN 1 THEN 672
            WHEN 2 THEN 558
            WHEN 3 THEN 624
            ELSE 690
        END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE l.seq
                WHEN 0 THEN 0
                WHEN 1 THEN 1
                WHEN 2 THEN 3
                WHEN 3 THEN 5
                ELSE 8
            END,
            DATE(p.create_time)
        )
    ) AS create_time,
    TIMESTAMPADD(
        MINUTE,
        CASE l.seq
            WHEN 0 THEN 606
            WHEN 1 THEN 672
            WHEN 2 THEN 558
            WHEN 3 THEN 624
            ELSE 690
        END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE l.seq
                WHEN 0 THEN 0
                WHEN 1 THEN 1
                WHEN 2 THEN 3
                WHEN 3 THEN 5
                ELSE 8
            END,
            DATE(p.create_time)
        )
    ) AS modify_time,
    0 AS version,
    0 AS deleted,
    980001 AS tenant_id,
    990001 AS tenant_plat_id,
    p.id AS player_id,
    p.username AS player_username,
    CONCAT('10.30.', FLOOR(p.player_seq / 32), '.', l.seq + 1) AS ip,
    p.regist_device AS device,
    p.regist_address AS address,
    p.channel_id AS channel_id,
    CASE WHEN l.seq = 4 THEN 2 ELSE 1 END AS category,
    CASE l.seq
        WHEN 0 THEN 0
        WHEN 1 THEN 8640
        WHEN 2 THEN 25920
        WHEN 3 THEN 43200
        ELSE 69120
    END AS interval_time,
    p.device_key AS device_key,
    p.channel_id AS login_channel_id,
    p.regist_domain AS login_domain,
    TIMESTAMPADD(
        MINUTE,
        CASE l.seq
            WHEN 0 THEN 606
            WHEN 1 THEN 672
            WHEN 2 THEN 558
            WHEN 3 THEN 624
            ELSE 690
        END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE l.seq
                WHEN 0 THEN 0
                WHEN 1 THEN 1
                WHEN 2 THEN 3
                WHEN 3 THEN 5
                ELSE 8
            END,
            DATE(p.create_time)
        )
    ) AS s_create_time
FROM (
    SELECT p.*, p.id - 990200 AS player_seq, MOD(p.id - 990200, 4) AS slot
    FROM dim_player p
    WHERE p.tenant_plat_id = 990001
      AND p.id BETWEEN 990200 AND 990459
) p
CROSS JOIN (
    SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
) l;
INSERT INTO dwd_order_deposit (
    id, create_time, modify_time, version, deleted,
    tenant_id, tenant_plat_id,
    player_id, player_username,
    status, amount, channel_id,
    pay_type_id, pay_mode_id, third_order_no, third_trade_date,
    actual_amount, device, finished_time, remark,
    bank_transfer_id, times, callback_time,
    operate_remark, amount_before, amount_after,
    regist_time, pay_account_change_log_id,
    ip, pay_type_group_name, pay_acct_name, pay_acct_no, pay_bank_name,
    s_create_time, vip_id
)
SELECT
    1002001 + p.player_seq * 4 + d.seq AS id,
    TIMESTAMPADD(
        MINUTE,
        CASE d.seq WHEN 0 THEN 605 WHEN 1 THEN 610 WHEN 2 THEN 615 ELSE 620 END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE d.seq WHEN 0 THEN 0 WHEN 1 THEN 2 WHEN 2 THEN 4 ELSE 7 END,
            DATE(p.create_time)
        )
    ) AS create_time,
    TIMESTAMPADD(
        MINUTE,
        CASE d.seq WHEN 0 THEN 605 WHEN 1 THEN 610 WHEN 2 THEN 615 ELSE 620 END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE d.seq WHEN 0 THEN 0 WHEN 1 THEN 2 WHEN 2 THEN 4 ELSE 7 END,
            DATE(p.create_time)
        )
    ) AS modify_time,
    0 AS version,
    0 AS deleted,
    980001 AS tenant_id,
    990001 AS tenant_plat_id,
    p.id AS player_id,
    p.username AS player_username,
    2 AS status,
    CASE d.seq
        WHEN 0 THEN 60 + p.slot * 10 + p.cohort_bonus
        WHEN 1 THEN 90 + p.slot * 15 + p.cohort_bonus
        WHEN 2 THEN 140 + p.slot * 20 + p.cohort_bonus
        ELSE 220 + p.slot * 25 + p.cohort_bonus
    END AS amount,
    p.channel_id AS channel_id,
    1 AS pay_type_id,
    1 AS pay_mode_id,
    CONCAT('DEP-', 1002001 + p.player_seq * 4 + d.seq) AS third_order_no,
    DATE(
        TIMESTAMPADD(
            MINUTE,
            CASE d.seq WHEN 0 THEN 605 WHEN 1 THEN 610 WHEN 2 THEN 615 ELSE 620 END + p.slot * 7,
            TIMESTAMPADD(
                DAY,
                CASE d.seq WHEN 0 THEN 0 WHEN 1 THEN 2 WHEN 2 THEN 4 ELSE 7 END,
                DATE(p.create_time)
            )
        )
    ) AS third_trade_date,
    CASE d.seq
        WHEN 0 THEN 60 + p.slot * 10 + p.cohort_bonus
        WHEN 1 THEN 90 + p.slot * 15 + p.cohort_bonus
        WHEN 2 THEN 140 + p.slot * 20 + p.cohort_bonus
        ELSE 220 + p.slot * 25 + p.cohort_bonus
    END AS actual_amount,
    p.regist_device AS device,
    TIMESTAMPADD(
        MINUTE,
        CASE d.seq WHEN 0 THEN 605 WHEN 1 THEN 610 WHEN 2 THEN 615 ELSE 620 END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE d.seq WHEN 0 THEN 0 WHEN 1 THEN 2 WHEN 2 THEN 4 ELSE 7 END,
            DATE(p.create_time)
        )
    ) AS finished_time,
    CONCAT('Mass ', p.id, ' deposit ', d.seq + 1) AS remark,
    0 AS bank_transfer_id,
    d.seq + 1 AS times,
    TIMESTAMPADD(
        MINUTE,
        CASE d.seq WHEN 0 THEN 605 WHEN 1 THEN 610 WHEN 2 THEN 615 ELSE 620 END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE d.seq WHEN 0 THEN 0 WHEN 1 THEN 2 WHEN 2 THEN 4 ELSE 7 END,
            DATE(p.create_time)
        )
    ) AS callback_time,
    'seed-bulk' AS operate_remark,
    CASE d.seq
        WHEN 0 THEN 0
        WHEN 1 THEN 60 + p.slot * 10 + p.cohort_bonus
        WHEN 2 THEN 150 + p.slot * 25 + p.cohort_bonus * 2
        ELSE 290 + p.slot * 45 + p.cohort_bonus * 3
    END AS amount_before,
    CASE d.seq
        WHEN 0 THEN 60 + p.slot * 10 + p.cohort_bonus
        WHEN 1 THEN 150 + p.slot * 25 + p.cohort_bonus * 2
        WHEN 2 THEN 290 + p.slot * 45 + p.cohort_bonus * 3
        ELSE 510 + p.slot * 70 + p.cohort_bonus * 4
    END AS amount_after,
    p.create_time AS regist_time,
    0 AS pay_account_change_log_id,
    CONCAT('10.40.', FLOOR(p.player_seq / 32), '.', d.seq + 1) AS ip,
    'bank' AS pay_type_group_name,
    'acct' AS pay_acct_name,
    CONCAT('62220000', p.id) AS pay_acct_no,
    'KB Bank' AS pay_bank_name,
    TIMESTAMPADD(
        MINUTE,
        CASE d.seq WHEN 0 THEN 605 WHEN 1 THEN 610 WHEN 2 THEN 615 ELSE 620 END + p.slot * 7,
        TIMESTAMPADD(
            DAY,
            CASE d.seq WHEN 0 THEN 0 WHEN 1 THEN 2 WHEN 2 THEN 4 ELSE 7 END,
            DATE(p.create_time)
        )
    ) AS s_create_time,
    p.vip_id AS vip_id
FROM (
    SELECT
        p.*,
        p.id - 990200 AS player_seq,
        MOD(p.id - 990200, 4) AS slot,
        MOD(FLOOR((p.id - 990200) / 4), 5) * 10 AS cohort_bonus
    FROM dim_player p
    WHERE p.tenant_plat_id = 990001
      AND p.id BETWEEN 990200 AND 990459
) p
CROSS JOIN (
    SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3
) d;
INSERT INTO dwd_order_withdrawal (
    id, create_time, modify_time, version, deleted,
    auditor_id, tenant_id, tenant_plat_id,
    player_id, player_username,
    status, amount, channel_id,
    account_name, account_no, bank_name, bank_province, bank_city, bank_address,
    third_order_no, third_trade_date, follower_id,
    finished_time, remark, times, device,
    callback_time, callback_remark,
    audit_time, audit_remark, operate_remark,
    amount_before, amount_after,
    ip, pay_account_change_log_id, pay_mode_id, withdrawal_type_id,
    receive_time, split_flag, main_order_no, fee_amount, act_amount,
    audit_step, audit_times, audit_amount, risk_status, order_risk_type,
    withdrawal_type, s_create_time
)
SELECT
    1006001 + FLOOR(p.player_seq / 7) AS id,
    TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time))) AS create_time,
    TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time))) AS modify_time,
    0 AS version,
    0 AS deleted,
    980002 AS auditor_id,
    980001 AS tenant_id,
    990001 AS tenant_plat_id,
    p.id AS player_id,
    p.username AS player_username,
    3 AS status,
    ROUND(dep.deposit_total * (0.12 + p.slot * 0.01), 4) AS amount,
    p.channel_id AS channel_id,
    p.real_name AS account_name,
    CONCAT('621799', p.id) AS account_no,
    'KB Bank' AS bank_name,
    p.regist_address AS bank_province,
    p.regist_address AS bank_city,
    p.regist_address AS bank_address,
    CONCAT('WD-', 1006001 + FLOOR(p.player_seq / 7)) AS third_order_no,
    DATE(TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time)))) AS third_trade_date,
    0 AS follower_id,
    TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time))) AS finished_time,
    CONCAT('Mass ', p.id, ' withdraw') AS remark,
    2 AS times,
    p.regist_device AS device,
    TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time))) AS callback_time,
    'success' AS callback_remark,
    TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time))) AS audit_time,
    'pass' AS audit_remark,
    'seed-bulk' AS operate_remark,
    dep.deposit_total AS amount_before,
    ROUND(dep.deposit_total - dep.deposit_total * (0.12 + p.slot * 0.01), 4) AS amount_after,
    p.regist_ip AS ip,
    0 AS pay_account_change_log_id,
    1 AS pay_mode_id,
    1 AS withdrawal_type_id,
    TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time))) AS receive_time,
    0 AS split_flag,
    0 AS main_order_no,
    0.0000 AS fee_amount,
    ROUND(dep.deposit_total * (0.12 + p.slot * 0.01), 4) AS act_amount,
    1 AS audit_step,
    1 AS audit_times,
    ROUND(dep.deposit_total * (0.12 + p.slot * 0.01), 4) AS audit_amount,
    0 AS risk_status,
    0 AS order_risk_type,
    1 AS withdrawal_type,
    TIMESTAMPADD(MINUTE, 1080 + p.slot * 9, TIMESTAMPADD(DAY, 10 + MOD(p.player_seq, 3), DATE(p.create_time))) AS s_create_time
FROM (
    SELECT p.*, p.id - 990200 AS player_seq, MOD(p.id - 990200, 4) AS slot
    FROM dim_player p
    WHERE p.tenant_plat_id = 990001
      AND p.id BETWEEN 990200 AND 990459
      AND MOD(p.id - 990200, 7) = 0
) p
JOIN (
    SELECT player_id, ROUND(SUM(amount), 4) AS deposit_total
    FROM dwd_order_deposit
    WHERE tenant_plat_id = 990001
      AND status = 2
      AND player_id BETWEEN 990200 AND 990459
    GROUP BY player_id
) dep ON dep.player_id = p.id;
INSERT INTO dwd_bet_order (
    id, create_time, modify_time, version, deleted,
    bet_time, settle_time,
    tenant_id, tenant_plat_id,
    player_id, game_id, game_name,
    game_line_id, game_line_series_id, game_type_id,
    channel_id, rebate_agent_id,
    third_order_no, settle_status,
    bet_amount, win_loss_amount, valid_bet_amount,
    extend_valid_bet_amount, extend_win_loss_amount,
    insurance_bet, insurance_win, take,
    bet_content, rebated, bet_game_type_id, batch_no, s_create_time
)
SELECT
    1008001 + x.player_seq * 5 + x.bet_seq AS id,
    x.bet_time AS create_time,
    x.bet_time AS modify_time,
    0 AS version,
    0 AS deleted,
    x.bet_time AS bet_time,
    TIMESTAMPADD(MINUTE, 5, x.bet_time) AS settle_time,
    980001 AS tenant_id,
    990001 AS tenant_plat_id,
    x.player_id AS player_id,
    g.id AS game_id,
    g.name AS game_name,
    g.game_line_id AS game_line_id,
    g.game_line_series_id AS game_line_series_id,
    g.game_type_id AS game_type_id,
    x.channel_id AS channel_id,
    CASE x.slot
        WHEN 0 THEN 980031
        WHEN 1 THEN 980032
        WHEN 2 THEN 980031
        ELSE 980032
    END AS rebate_agent_id,
    CONCAT('BET-', 1008001 + x.player_seq * 5 + x.bet_seq) AS third_order_no,
    1 AS settle_status,
    x.bet_amount AS bet_amount,
    ROUND(
        CASE x.bet_seq
            WHEN 0 THEN x.bet_amount * -0.11
            WHEN 1 THEN x.bet_amount * 0.06
            WHEN 2 THEN x.bet_amount * 0.13
            WHEN 3 THEN x.bet_amount * -0.04
            ELSE x.bet_amount * 0.09
        END,
        4
    ) AS win_loss_amount,
    x.bet_amount AS valid_bet_amount,
    0.0000 AS extend_valid_bet_amount,
    0.0000 AS extend_win_loss_amount,
    0.0000 AS insurance_bet,
    0.0000 AS insurance_win,
    0.0000 AS take,
    CONCAT(x.player_username, ' bulk bet ', x.bet_seq + 1) AS bet_content,
    0 AS rebated,
    g.bet_game_type_id AS bet_game_type_id,
    CONCAT('KB-BULK-', 1008001 + x.player_seq * 5 + x.bet_seq) AS batch_no,
    x.bet_time AS s_create_time
FROM (
    SELECT
        p.id AS player_id,
        p.username AS player_username,
        p.channel_id,
        p.id - 990200 AS player_seq,
        MOD(p.id - 990200, 4) AS slot,
        b.seq AS bet_seq,
        TIMESTAMPADD(
            MINUTE,
            CASE b.seq
                WHEN 0 THEN 780
                WHEN 1 THEN 840
                WHEN 2 THEN 900
                WHEN 3 THEN 960
                ELSE 1020
            END + MOD(p.id - 990200, 4) * 10,
            TIMESTAMPADD(
                DAY,
                CASE b.seq
                    WHEN 0 THEN 0
                    WHEN 1 THEN 1
                    WHEN 2 THEN 2
                    WHEN 3 THEN 4
                    ELSE 7
                END,
                DATE(p.create_time)
            )
        ) AS bet_time,
        100 + MOD(p.id - 990200, 4) * 15 + b.seq * 20 AS bet_amount,
        CASE MOD(p.id - 990200, 4)
            WHEN 0 THEN CASE b.seq WHEN 0 THEN 880003 WHEN 1 THEN 880005 WHEN 2 THEN 880007 WHEN 3 THEN 880013 ELSE 880011 END
            WHEN 1 THEN CASE b.seq WHEN 0 THEN 880006 WHEN 1 THEN 880009 WHEN 2 THEN 880008 WHEN 3 THEN 880015 ELSE 880014 END
            WHEN 2 THEN CASE b.seq WHEN 0 THEN 880012 WHEN 1 THEN 880010 WHEN 2 THEN 880018 WHEN 3 THEN 880016 ELSE 880017 END
            ELSE CASE b.seq WHEN 0 THEN 880013 WHEN 1 THEN 880011 WHEN 2 THEN 880021 WHEN 3 THEN 880019 ELSE 880020 END
        END AS game_id
    FROM dim_player p
    CROSS JOIN (
        SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
    ) b
    WHERE p.tenant_plat_id = 990001
      AND p.id BETWEEN 990200 AND 990459
) x
JOIN `dim_game` g ON g.id = x.game_id;
INSERT INTO bds_bet_order_detail (
    id, create_time, modify_time, version, deleted,
    bet_time, settle_time,
    tenant_id, tenant_plat_id,
    player_id, game_id, game_name,
    game_line_id, game_line_series_id, game_type_id,
    channel_id, rebate_agent_id,
    third_order_no, settle_status,
    bet_amount, win_loss_amount, valid_bet_amount,
    bet_content, bet_game_type_id, source_type
)
SELECT
    id, create_time, modify_time, 1 AS version, deleted,
    bet_time, settle_time,
    tenant_id, tenant_plat_id,
    player_id, game_id, game_name,
    game_line_id, game_line_series_id, game_type_id,
    channel_id, rebate_agent_id,
    third_order_no, settle_status,
    bet_amount, win_loss_amount, valid_bet_amount,
    bet_content, bet_game_type_id, 1 AS source_type
FROM dwd_bet_order
WHERE tenant_plat_id = 990001
  AND player_id BETWEEN 990200 AND 990459
  AND id BETWEEN 1008001 AND 1009300;
INSERT INTO bds_bet_order_person_chess_and_card_extend (
    id, create_time, modify_time, version, deleted,
    tenant_id, tenant_plat_id, bet_time, settle_time,
    game_id, game_line_series_id, game_type_id, bet_game_type_id,
    channel_id, player_id, game_line_id, game_username,
    third_order_no, bet_order_id, settle_status,
    insurance_win, insurance_bet, extend_win_loss_amount, take, extend_valid_bet_amount, win_loss_amount
)
SELECT
    1012001 + (o.player_id - 990200) AS id,
    o.create_time,
    o.settle_time,
    1 AS version,
    0 AS deleted,
    o.tenant_id,
    o.tenant_plat_id,
    o.bet_time,
    o.settle_time,
    o.game_id,
    o.game_line_series_id,
    o.game_type_id,
    o.bet_game_type_id,
    o.channel_id,
    o.player_id,
    o.game_line_id,
    CONCAT('kb_m', o.player_id, '_game') AS game_username,
    o.third_order_no,
    o.id AS bet_order_id,
    o.settle_status,
    0.0000 AS insurance_win,
    0.0000 AS insurance_bet,
    ROUND(o.win_loss_amount * 0.8, 4) AS extend_win_loss_amount,
    ROUND(o.bet_amount * 0.05, 4) AS take,
    ROUND(o.valid_bet_amount * 0.9, 4) AS extend_valid_bet_amount,
    o.win_loss_amount
FROM dwd_bet_order o
WHERE o.tenant_plat_id = 990001
  AND o.player_id BETWEEN 990200 AND 990459
  AND o.id BETWEEN 1008001 AND 1009300
  AND o.bet_game_type_id = 990033;
INSERT INTO `dim_channel_player_statistics_of_day` (
    id, create_time, modify_time, version, deleted,
    tenant_id, tenant_plat_id, channel_id,
    biz_date, regist_num, first_deposit_num,
    win_amount, first_deposit_amount
)
SELECT
    1016001 + d.day_seq * 4 + c.channel_slot AS id,
    TIMESTAMPADD(SECOND, 86399, TIMESTAMPADD(DAY, d.day_seq, '2026-04-15 00:00:00')) AS create_time,
    TIMESTAMPADD(SECOND, 86399, TIMESTAMPADD(DAY, d.day_seq, '2026-04-15 00:00:00')) AS modify_time,
    1 AS version,
    0 AS deleted,
    980001 AS tenant_id,
    990001 AS tenant_plat_id,
    c.channel_id,
    TIMESTAMPADD(DAY, d.day_seq, '2026-04-15 00:00:00') AS biz_date,
    COALESCE(r.regist_num, 0) AS regist_num,
    COALESCE(fd.first_deposit_num, 0) AS first_deposit_num,
    COALESCE(w.win_amount, 0.0000) AS win_amount,
    COALESCE(fd.first_deposit_amount, 0.0000) AS first_deposit_amount
FROM (
    SELECT ones.n + tens.n * 10 AS day_seq
    FROM (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
        UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9
    ) ones
    CROSS JOIN (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
        UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7
    ) tens
    WHERE ones.n + tens.n * 10 < 12
) d
CROSS JOIN (
    SELECT 0 AS channel_slot, 990011 AS channel_id
    UNION ALL SELECT 1, 990012
    UNION ALL SELECT 2, 990013
    UNION ALL SELECT 3, 990014
) c
LEFT JOIN (
    SELECT DATE(create_time) AS biz_date, channel_id, COUNT(*) AS regist_num
    FROM dim_player
    WHERE tenant_plat_id = 990001
      AND id BETWEEN 990200 AND 990459
    GROUP BY DATE(create_time), channel_id
) r
  ON r.biz_date = DATE(TIMESTAMPADD(DAY, d.day_seq, '2026-04-15 00:00:00'))
 AND r.channel_id = c.channel_id
LEFT JOIN (
    SELECT DATE(create_time) AS biz_date, channel_id, COUNT(*) AS first_deposit_num, ROUND(SUM(amount), 4) AS first_deposit_amount
    FROM dwd_order_deposit
    WHERE tenant_plat_id = 990001
      AND player_id BETWEEN 990200 AND 990459
      AND status = 2
      AND times = 1
    GROUP BY DATE(create_time), channel_id
) fd
  ON fd.biz_date = DATE(TIMESTAMPADD(DAY, d.day_seq, '2026-04-15 00:00:00'))
 AND fd.channel_id = c.channel_id
LEFT JOIN (
    SELECT DATE(bet_time) AS biz_date, channel_id, ROUND(SUM(win_loss_amount), 4) AS win_amount
    FROM dwd_bet_order
    WHERE tenant_plat_id = 990001
      AND player_id BETWEEN 990200 AND 990459
      AND id BETWEEN 1008001 AND 1009300
    GROUP BY DATE(bet_time), channel_id
) w
  ON w.biz_date = DATE(TIMESTAMPADD(DAY, d.day_seq, '2026-04-15 00:00:00'))
 AND w.channel_id = c.channel_id;
COMMIT;
